import React, { useState } from 'react';
import {
  Monitor, Cpu, CheckCircle, FileText, Gift,
  ChevronRight, Users, Calendar, Award, ArrowRight
} from 'lucide-react';
import './AsistenPage.css';

const posisiData = {
  Hardware: [
    {
      title: 'Asisten Lab Robotika',
      desc: 'Membantu praktikum robotika, membimbing mahasiswa dalam penggunaan perangkat keras dan sensor.',
      slots: 5,
      icon: Cpu,
    },
    {
      title: 'Asisten Lab Elektronika',
      desc: 'Mendampingi praktikum elektronika dasar, rangkaian DC/AC, dan PCB assembly.',
      slots: 4,
      icon: Cpu,
    },
  ],
  Software: [
    {
      title: 'Asisten Lab Pemrograman',
      desc: 'Membantu praktikum pemrograman Python, C++, dan pengembangan aplikasi berbasis IoT.',
      slots: 6,
      icon: Monitor,
    },
    {
      title: 'Asisten Lab AI/ML',
      desc: 'Mendampingi praktikum machine learning, computer vision, dan pengolahan data.',
      slots: 3,
      icon: Monitor,
    },
  ],
};

const roadmapSteps = [
  { step: '01', title: 'Buka Pendaftaran', desc: 'Formulir pendaftaran dibuka setiap awal semester' },
  { step: '02', title: 'Isi Formulir', desc: 'Lengkapi data diri, IPK, dan posisi yang diminati' },
  { step: '03', title: 'Seleksi Berkas', desc: 'Tim lab menyeleksi berkas yang masuk' },
  { step: '04', title: 'Tes & Wawancara', desc: 'Peserta lolos berkas mengikuti tes teknis dan wawancara' },
  { step: '05', title: 'Pengumuman', desc: 'Hasil seleksi diumumkan melalui website dan Instagram' },
  { step: '06', title: 'Onboarding', desc: 'Asisten terpilih mengikuti pelatihan sebelum mulai bertugas' },
];

const ketentuanData = [
  {
    icon: CheckCircle,
    title: 'Requirements',
    color: 'purple',
    items: [
      'Mahasiswa aktif min. semester 3',
      'IPK minimal 3.00',
      'Menguasai bidang yang dilamar',
      'Bersedia hadir sesuai jadwal',
      'Belum pernah dikenai sanksi akademik',
    ],
  },
  {
    icon: FileText,
    title: 'Dokumen',
    color: 'blue',
    items: [
      'KTM (Kartu Tanda Mahasiswa)',
      'Transkrip nilai terbaru',
      'CV / Resume',
      'Sertifikat pendukung (jika ada)',
      'Foto 3x4 terbaru',
    ],
  },
  {
    icon: Gift,
    title: 'Keuntungan',
    color: 'emerald',
    items: [
      'Sertifikat resmi dari lab',
      'Pengembangan skill teknis',
      'Jaringan profesional',
      'Prioritas workshop eksklusif',
      'Honorarium bulanan',
    ],
  },
];

export default function PendaftaranAsistenPage() {
  const [activeTab, setActiveTab] = useState('Hardware');

  return (
    <>
      {/* HEADER */}
      <section className="page-header">
        <div className="container">
          <h1>Pendaftaran Asisten</h1>
          <p>Bergabunglah sebagai asisten lab dan kembangkan skill-mu bersama kami</p>
        </div>
      </section>

      {/* SECTION POSISI */}
      <section className="asisten-section">
        <div className="container">

          {/* Intro Asisten */}
          <div className="asisten-intro">
            <div className="asisten-intro-text">
              <div className="about-badge">Asisten Lab</div>
              <h2>Jadilah Bagian dari Tim Kami</h2>
              <p>
                Asisten laboratorium adalah mahasiswa berprestasi yang bertugas membantu
                pelaksanaan praktikum, membimbing rekan sejawat, dan menjaga operasional lab.
                Posisi ini terbuka untuk dua divisi utama: Hardware dan Software.
              </p>
              <div className="asisten-stats">
                <div className="asisten-stat">
                  <Users size={20} />
                  <div>
                    <strong>30+</strong>
                    <span>Asisten Aktif</span>
                  </div>
                </div>
                <div className="asisten-stat">
                  <Award size={20} />
                  <div>
                    <strong>2 Divisi</strong>
                    <span>Hardware & Software</span>
                  </div>
                </div>
                <div className="asisten-stat">
                  <Calendar size={20} />
                  <div>
                    <strong>2x / Tahun</strong>
                    <span>Buka Pendaftaran</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Tab Hardware / Software */}
          <div className="posisi-tab-menu">
            {['Hardware', 'Software'].map(tab => (
              <button
                key={tab}
                className={`posisi-tab-btn ${activeTab === tab ? 'active' : ''}`}
                onClick={() => setActiveTab(tab)}
              >
                {tab === 'Hardware' ? <Cpu size={16} /> : <Monitor size={16} />}
                {tab}
              </button>
            ))}
          </div>

          {/* Cards Posisi */}
          <div className="posisi-grid">
            {posisiData[activeTab].map((posisi, i) => {
              const Icon = posisi.icon;
              return (
                <div key={i} className={`posisi-card posisi-card-${activeTab.toLowerCase()}`}>
                  <div className="posisi-card-icon">
                    <Icon size={28} />
                  </div>
                  <h3>{posisi.title}</h3>
                  <p>{posisi.desc}</p>
                  <div className="posisi-slots">
                    <Users size={14} />
                    <span>{posisi.slots} slot tersedia</span>
                  </div>
                </div>
              );
            })}
          </div>

          {/* ROADMAP */}
          <div className="roadmap-section">
            <div className="about-header">
              <div className="about-badge">Alur</div>
              <h2>Roadmap Pendaftaran Asisten</h2>
              <p>Ikuti langkah-langkah berikut untuk menjadi asisten laboratorium</p>
            </div>
            <div className="roadmap-grid">
              {roadmapSteps.map((step, i) => (
                <div key={i} className="roadmap-card">
                  <div className="roadmap-step">{step.step}</div>
                  <div className="roadmap-arrow">
                    {i < roadmapSteps.length - 1 && <ArrowRight size={16} />}
                  </div>
                  <h4>{step.title}</h4>
                  <p>{step.desc}</p>
                </div>
              ))}
            </div>
          </div>

          {/* KETENTUAN */}
          <div className="ketentuan-section">
            <div className="about-header">
              <div className="about-badge">Ketentuan</div>
              <h2>Syarat & Ketentuan</h2>
              <p>Pastikan kamu memenuhi semua persyaratan sebelum mendaftar</p>
            </div>
            <div className="ketentuan-grid">
              {ketentuanData.map((item, i) => {
                const Icon = item.icon;
                return (
                  <div key={i} className={`ketentuan-card ketentuan-${item.color}`}>
                    <div className="ketentuan-header">
                      <div className="ketentuan-icon">
                        <Icon size={22} />
                      </div>
                      <h3>{item.title}</h3>
                    </div>
                    <ul className="ketentuan-list">
                      {item.items.map((point, j) => (
                        <li key={j}>
                          <ChevronRight size={14} />
                          <span>{point}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                );
              })}
            </div>
          </div>

          {/* DAFTAR BUTTON */}
          <div className="daftar-section">
            <div className="daftar-box">
              <h2>Siap Bergabung?</h2>
              <p>Pendaftaran dibuka setiap awal semester. Pastikan semua dokumen sudah disiapkan.</p>
              <button className="btn-daftar">
                <FileText size={18} />
                Daftar Sekarang
              </button>
            </div>
          </div>

        </div>
      </section>
    </>
  );
}
